changeSet.sql:
create procedure create_cpr_spmn_stats( in in_last_id bigint, in in_chunk_size int, out out_last_id bigint ) begin declare v_last_id bigint;
if in_last_id = 0 then drop table if exists tmp_os_cpr_spmn_stats;
create table tmp_os_cpr_spmn_stats ( identifier bigint, specimens_collected int, specimens_missed int, specimens_not_collected int, specimens_pending int ); end if;
select max(identifier) into v_last_id from ( select identifier from catissue_coll_prot_reg where identifier > in_last_id order by identifier limit in_chunk_size ) t;
if v_last_id is not null then insert into tmp_os_cpr_spmn_stats (identifier, specimens_collected, specimens_missed, specimens_not_collected, specimens_pending) select cpr.identifier as identifier, count(distinct case when spmn.collection_status = 'Collected' then spmn.identifier else null end) as specimens_collected, count(distinct case when spmn.collection_status = 'Missed Collection' then spmn.identifier else null end ) as specimens_missed, count(distinct case when spmn.collection_status = 'Not Collected' then spmn.identifier else null end ) as specimens_not_collected, count(distinct case when ((sr.identifier is not null and spmn.identifier is null) or spmn.collection_status = 'Pending') then case when (spmn.identifier is not null and spmn.req_specimen_id is null) then concat('s', spmn.identifier) else concat('sr', sr.identifier) end else null end ) as specimens_pending from catissue_coll_prot_reg cpr left join catissue_coll_prot_event cpe on cpe.collection_protocol_id = cpr.collection_protocol_id and cpe.activity_status != 'Disabled' left join catissue_cp_req_specimen sr on sr.collection_protocol_event_id = cpe.identifier and sr.activity_status != 'Disabled' left join catissue_specimen_coll_group visit on (visit.collection_protocol_event_id = cpe.identifier or visit.collection_protocol_event_id is null) and visit.collection_protocol_reg_id = cpr.identifier and visit.activity_status != 'Disabled' left join catissue_specimen spmn on (spmn.req_specimen_id is null or spmn.req_specimen_id = sr.identifier) and spmn.specimen_collection_group_id = visit.identifier and spmn.activity_status != 'Disabled' where cpr.identifier > in_last_id and cpr.identifier <= v_last_id group by cpr.identifier; end if;
set out_last_id = ifnull(v_last_id, in_last_id); end; //

create procedure refresh_cpr_spmn_stats(
  in in_last_id bigint,
  in in_chunk_size int,
  out out_last_id bigint
)
begin
  call create_cpr_spmn_stats(in_last_id, in_chunk_size, out_last_id);

  if out_last_id = in_last_id then
    drop table if exists os_cpr_spmn_stats;

    alter table tmp_os_cpr_spmn_stats rename os_cpr_spmn_stats;

    create index os_cpr_spmn_stats_idx on os_cpr_spmn_stats (identifier);
  end if;
end;
//

create or replace procedure create_cpr_spmn_stats( in_last_id in number, in_chunk_size in number, out_last_id out number ) AUTHID CURRENT_USER is v_last_id number; begin if in_last_id = 0 then drop_table_if_exists('tmp_os_cpr_spmn_stats');
execute immediate 'create table tmp_os_cpr_spmn_stats ( identifier number(19), specimens_collected number(10), specimens_missed number(10), specimens_not_collected number(10), specimens_pending number(10) )'; end if;
select max(identifier) into v_last_id from ( select identifier from ( select identifier from catissue_coll_prot_reg where identifier > in_last_id order by identifier ) where rownum <= in_chunk_size );
if v_last_id is not null then execute immediate 'insert into tmp_os_cpr_spmn_stats (identifier, specimens_collected, specimens_missed, specimens_not_collected, specimens_pending) select cpr.identifier as identifier, count(distinct case when spmn.collection_status = ''Collected'' then spmn.identifier else null end) as specimens_collected, count(distinct case when spmn.collection_status = ''Missed Collection'' then spmn.identifier else null end ) as specimens_missed, count(distinct case when spmn.collection_status = ''Not Collected'' then spmn.identifier else null end) as specimens_not_collected, count(distinct case when ((sr.identifier is not null and spmn.identifier is null) or spmn.collection_status = ''Pending'') then case when (spmn.identifier is not null and spmn.req_specimen_id is null) then concat(''s'', spmn.identifier) else concat(''sr'', sr.identifier) end else null end ) as specimens_pending from catissue_coll_prot_reg cpr left join catissue_coll_prot_event cpe on cpe.collection_protocol_id = cpr.collection_protocol_id and cpe.activity_status != ''Disabled'' left join catissue_cp_req_specimen sr on sr.collection_protocol_event_id = cpe.identifier and sr.activity_status != ''Disabled'' left join catissue_specimen_coll_group visit on (visit.collection_protocol_event_id = cpe.identifier or visit.collection_protocol_event_id is null) and visit.collection_protocol_reg_id = cpr.identifier and visit.activity_status != ''Disabled'' left join catissue_specimen spmn on (spmn.req_specimen_id is null or spmn.req_specimen_id = sr.identifier) and spmn.specimen_collection_group_id = visit.identifier and spmn.activity_status != ''Disabled'' where cpr.identifier > ' || in_last_id || ' and cpr.identifier <= ' || v_last_id || ' group by cpr.identifier'; end if;
out_last_id := nvl(v_last_id, in_last_id); end; //

create or replace procedure refresh_cpr_spmn_stats(
  in_last_id in number,
  in_chunk_size in number,
  out_last_id out number
) AUTHID CURRENT_USER is
begin
  create_cpr_spmn_stats(in_last_id, in_chunk_size, out_last_id);
  if out_last_id = in_last_id then
    declare
      table_does_not_exist exception;
      pragma exception_init(table_does_not_exist, -942); -- ORA-00942
    begin
      execute immediate 'drop table os_cpr_spmn_stats';
    exception
      when table_does_not_exist then null;
    end;

    execute immediate 'alter table tmp_os_cpr_spmn_stats rename to os_cpr_spmn_stats';

    execute immediate 'create index os_cpr_spmn_stats_idx on os_cpr_spmn_stats (identifier)';
  end if;
end;
//
